  TabletPortrait: '(min-width: 600px) and (max-width: 1279.98px) and (orientation: portrait)',
  WebPortrait: '(min-width: 1280px) and (orientation: portrait)',
  HandsetLandscape: '(max-width: 959.98px) and (orientation: landscape)',
