```go
package main

import (
	"fmt"
	"github.com/golang-jwt/jwt/v5"
	echojwt "github.com/labstack/echo-jwt/v4"
	"github.com/labstack/echo/v4"
	"net/http"

	"time"
)

type User struct {
	Name string
	Age  int
}

type Claims struct {
	Name string `json:"name"`
	Age  int    `json:"age"`
	jwt.RegisteredClaims
}

var secretKey = []byte("secret")

func generateToken(user *User) (string, error) {
	claims := Claims{
		Name: user.Name,
		Age:  user.Age,
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(24 * time.Hour)),
			IssuedAt:  jwt.NewNumericDate(time.Now()),
			NotBefore: jwt.NewNumericDate(time.Now()),
			Issuer:    "your-app",
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)

	tokenString, err := token.SignedString(secretKey)
	if err != nil {
		return "", nil
	}

	return tokenString, nil
}

func main() {
	e := echo.New()

	user := User{
		Name: "Natish",
		Age:  6,
	}

	token, err := generateToken(&user)
	if err != nil {
		fmt.Println(err)
	}

	fmt.Println(token)

	// Grupo de rutas sin proteccion
	unprotected := e.Group("")
	unprotected.GET("/sss", func(c echo.Context) error {
		return c.JSON(http.StatusOK, "pocollossss")
	})

  // Grupo de rutas con proteccion
	protected := e.Group("")
	protected.Use(echojwt.WithConfig(echojwt.Config{
		SigningKey: secretKey,
		ErrorHandler: func(e echo.Context, err error) error {
			return echo.NewHTTPError(http.StatusUnauthorized, "invalid token")
		},
	}))

	protected.GET("/", func(c echo.Context) error {
		return c.JSON(http.StatusOK, "pocollo")
	})
	e.Logger.Fatal(e.Start(":1323"))
}

