```go
// WITH CONCURRENCY
package singleton

import "sync"

type PersonInterface interface {
	IncrementAge()
	GetAge() int
}

type person struct {
	name string
	age  int
}

var (
	p    *person
	once sync.Once // IMPORTANT
	mux  sync.Mutex // IMPORTANT
)

func NewPerson() PersonInterface {
  // IMPORTANT
	once.Do(func() {
		p = &person{}
	})

	return p
}

func (p *person) IncrementAge() {
	// IMPORTANT
	mux.Lock()
	p.setAge(p.age + 1)
	mux.Unlock()
}
