	sb.WriteString(t.Name)
	sb.WriteString(" - ")
	sb.WriteString(t.Responsable)
	sb.WriteString(" $")
	sb.WriteString(strconv.Itoa(t.Price()))
	sb.WriteString("\n")

	for _, subTask := range t.SubTask {
